<template><div class="panel-section"><h2 class="section-heading">匿名化匯出</h2><div class="card"><label><input type="checkbox" v-model="researchers"> 同時匿名化 Researcher</label><div class="form-group"><label class="form-label">額外掃描詞（每行一個）</label><textarea class="form-textarea" v-model="terms"></textarea></div><button class="btn btn-primary" @click="preview">產生匿名化預覽</button></div><div v-if="result" class="card"><div class="anonymize-warning">⚠️ {{result.warning}}</div><div v-for="(f,n) in result.findings" :key="n" class="redaction-row"><span><strong>{{f.term}}</strong> → {{f.replacement}}（{{f.source}}）</span><select class="form-select" v-model="f.decision"><option value="pending">待確認</option><option value="accept">接受遮蔽</option><option value="ignore">忽略</option></select></div><div class="btn-group"><button v-for="format in ['json','xlsx','csv']" :key="format" class="btn btn-secondary" :disabled="pending" @click="download(format)">匯出 {{format.toUpperCase()}}</button></div></div></div></template>
<script setup>import{ref,computed}from'vue';import{api}from'../api/client.js';import{useAppStore}from'../stores/appStore.js';const store=useAppStore(),researchers=ref(false),terms=ref(''),result=ref(null),pending=computed(()=>result.value?.findings.some(f=>f.decision==='pending'));async function preview(){result.value=await api(`/v1/projects/${store.currentProjectId}/exports/preview`,{method:'POST',body:{anonymize_researchers:researchers.value,additional_terms:terms.value.split('\n').map(x=>x.trim()).filter(Boolean)}})}async function download(format){const blob=await api(`/v1/projects/${store.currentProjectId}/exports`,{method:'POST',download:true,body:{format,anonymize_researchers:researchers.value,redactions:result.value.findings.map(({term,replacement,decision})=>({term,replacement,decision}))}}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`qualistream.${format}`;a.click();URL.revokeObjectURL(url)}</script>
